const body = items[0].json.body || items[0].json;
const monitor = body.monitor || {};
const heartbeat = body.heartbeat || {};
const msg = body.msg || "";

// Uptime Kuma status: 0 = DOWN, 1 = UP. Remediation only runs on DOWN events.
const isDown = heartbeat.status === 0 || msg.includes("DOWN");

let serviceName = "";
let targetHost = "";
let shouldTrigger = false;

if (isDown && monitor.name) {
  const monitorName = monitor.name;
  switch (monitorName) {
    case "Nextcloud":
      serviceName = "nextcloud-app";
      targetHost = "docker-01";
      shouldTrigger = true;
      break;
    case "Dozzle":
      serviceName = "dozzle";
      targetHost = "docker-01";
      shouldTrigger = true;
      break;
    case "n8n":
      serviceName = "n8n";
      targetHost = "automation-01";
      shouldTrigger = true;
      break;
    case "Semaphore":
      serviceName = "semaphore";
      targetHost = "automation-01";
      shouldTrigger = true;
      break;
    case "Portainer Agent":
      serviceName = "portainer_agent";
      targetHost = "docker-01";
      shouldTrigger = true;
      break;
    case "Homepage":
      serviceName = "homepage";
      targetHost = "automation-01";
      shouldTrigger = true;
      break;
    default:
      break;
  }
}

return [
  {
    json: {
      isDown,
      monitorName: monitor.name || "Unknown",
      serviceName,
      targetHost,
      shouldTrigger,
      msg
    }
  }
];
